        doc.setFontSize(9.5);
        doc.setTextColor(71, 85, 105);
        doc.text(wrappedLineText, margin, currentY);
        currentY += wrappedLineText.length * 4.5 + 8;

        // Draw pricing table
        const tableHeight = 45;
        checkPageSpace(tableHeight + 25);
        
        const tableY = currentY;
        
        // Header row
